import React, { useRef, useEffect, useState } from "react";
import "./App.css";

const getDimensions = ele => {
  const { height } = ele.getBoundingClientRect();
  const offsetTop = ele.offsetTop;
  const offsetBottom = offsetTop + height;

  return {
    height,
    offsetTop,
    offsetBottom,
  };
};

const scrollTo = ele => {
  ele.scrollIntoView({
    behavior: "smooth",
    block: "start",
  });
};

function App() {
  const [visibleSection, setVisibleSection] = useState();

  const headerRef = useRef(null);
  const introRef = useRef(null);
  const projectRef = useRef(null);
  const contactRef = useRef(null);

  const sectionRefs = [
    { section: "Introduction", ref: introRef },
    { section: "Projects", ref: projectRef },
    { section: "Contact", ref: contactRef },
  ];

  useEffect(() => {
    const handleScroll = () => {
      const { height: headerHeight } = getDimensions(headerRef.current);
      const scrollPosition = window.scrollY + headerHeight;

      const selected = sectionRefs.find(({ section, ref }) => {
        const ele = ref.current;
        if (ele) {
          const { offsetBottom, offsetTop } = getDimensions(ele);
          return scrollPosition > offsetTop && scrollPosition < offsetBottom;
        }
      });

      if (selected && selected.section !== visibleSection) {
        setVisibleSection(selected.section);
      } else if (!selected && visibleSection) {
        setVisibleSection(undefined);
      }
    };

    handleScroll();
    window.addEventListener("scroll", handleScroll);
    return () => {
      window.removeEventListener("scroll", handleScroll);
    };
  }, [visibleSection]);

  return (
    <div className="App">
      <div className="top-spacer" />

      <div className="content">
        <div className="sticky">
          <div className="header" ref={headerRef}>
            <button
              type="button"
              className={`header_link ${visibleSection === "Introduction" ? "selected" : ""}`}
              onClick={() => {
                scrollTo(introRef.current);
              }}
            >
              Introduction
            </button>
            <button
              type="button"
              className={`header_link ${visibleSection === "Projects" ? "selected" : ""}`}
              onClick={() => {
                scrollTo(projectRef.current);
              }}
            >
              Projects
            </button>
            <button
              type="button"
              className={`header_link ${visibleSection === "Contact" ? "selected" : ""}`}
              onClick={() => {
                scrollTo(contactRef.current);
              }}
            >
              Contact
            </button>
          </div>
        </div>
        <div className="section" id="Introduction" ref={introRef}>
          <p>
            <br></br>
            I am a recent Ph.D. graduate from the <a href="https://cogsci.ucmerced.edu/">Cogntive and Information Sciences Dept.</a>
            at the University of California, Merced.<br></br>
            I was advised by <a href="https://ucmerced.academia.edu/MichaelSpivey">Dr. Michael J. Spivey</a> on my thesis examining the complexity matching of gesture and gaze between a human listener and speaking virtual agent(s).<br></br>
            I received my Bachelor’s degree in Psychology from <a href="https://www.grinnell.edu/">Grinnell College</a> where I was heavily influenced by the teaching and work of <a href="https://sites.google.com/site/foovian/">Dr. Damian Kelty-Stephen.</a><br></br>
          </p>

          <h2 id="news">News</h2>
          <ul>
              <li>July, 2022. Poster at CogSci conference.</li>
              <li>April, 2022. Awarded (second) <strong>Honorable Mention</strong> for the National Science Foundation, Graduate Research Fellowship Program. </li>
              <li>May 22, 2021. Presented <strong>Talk</strong> at <a target="_blank" href="https://sites.google.com/view/camp-2021/home">California Meeting on Psycholinguistics (CAMP)</a> titled "Mouse-tracking meta-cognitive ratings of comprehension during garden-path sentences."</li>
              <li>April 21, 2020. Awarded <strong>Honorable Mention</strong> for the National Science Foundation, Graduate Research Fellowship Program.</li>
              <li>April 11, 2019. Presented <strong>Poster</strong> (<a target="_blank" href="https://docs.google.com/presentation/d/1xcG8i8NxYNNdRxuP5kzREJXfwmgciBBNQJMeR-7YaQc/edit?usp=sharing">Creating Meaningfully Distinct Risk Categories for Juvenile Recidivism Risk Assessment Tools.</a>) at Midwestern Psychological Association Conference.</li>
          </ul>
        </div>
        <div className="section" id="Projects" ref={projectRef}>

        </div>
        <div className="section" id="Contact" ref={contactRef}>

        </div>
      </div>

      <div className="bottom-spacer" />
    </div>
  );
}

export default App;
